executeFunc((function materialFilter(){if(typeof formDebounce!=="function"){return false}const form=document.forms.material_filter_form;if(typeof form==="undefined"){return false}form.addEventListener("click",(event=>{if(idFormDebounce==lastFormDebounce){clearTimeout(lastFormDebounce)}lastFormDebounce=idFormDebounce}));const inputFields=form.querySelectorAll("input, select, textarea");inputFields.forEach((field=>{if(field.id==="material_filter_form_category"||field.id==="material_filter_form_all"){field.addEventListener("change",(()=>{const material_filter_form_offer=form.material_filter_form_offer;if(typeof material_filter_form_offer==="object"){const options=material_filter_form_offer.options;for(var i=0;i<options.length;i++){options[i].selected=false}material_filter_form_offer.selectedIndex=0}setTimeout((()=>{form.submit()}),300)}));return}field.addEventListener("change",formDebounce((()=>{form.submit()}),1500))}));return true}));